def gen(rng, size):
    ops = ['ATM']
    args = [[]]
    for _ in range(max(1, size)):
        if rng.random() < 0.5:
            counts = [rng.randint(0, 5) for _ in range(5)]
            ops.append('deposit'); args.append([counts])
        else:
            amt = rng.randint(1, 200) * 20
            ops.append('withdraw'); args.append([amt])
    return [ops, args]

