class ATM:
    DENOMS = [20, 50, 100, 200, 500]
    def __init__(self):
        self.bills = [0, 0, 0, 0, 0]
    def deposit(self, banknotesCount):
        for i in range(5):
            self.bills[i] += banknotesCount[i]
    def withdraw(self, amount):
        take = [0, 0, 0, 0, 0]
        rem = amount
        i = 4
        while i >= 0:
            d = self.DENOMS[i]
            use = 0
            while use < self.bills[i] and d <= rem:
                use += 1
                rem -= d
            take[i] = use
            i -= 1
        if rem != 0:
            return [-1]
        for i in range(5):
            self.bills[i] -= take[i]
        return take

