class ATM:
    def __init__(self):
        self.denoms = [20, 50, 100, 200, 500]
        self.count = [0] * 5
    def deposit(self, banknotesCount):
        for i in range(5):
            self.count[i] += banknotesCount[i]
    def withdraw(self, amount):
        plan = [0] * 5
        for i in range(4, -1, -1):
            need = min(amount // self.denoms[i], self.count[i])
            plan[i] = need
            amount -= need * self.denoms[i]
        if amount != 0:
            return [-1]
        for i in range(5):
            self.count[i] -= plan[i]
        return plan

