class ATM {
    constructor() {
        this.denoms = [20, 50, 100, 200, 500];
        this.count = [0, 0, 0, 0, 0];
    }
    deposit(banknotesCount) {
        for (let i = 0; i < 5; i++) this.count[i] += banknotesCount[i];
    }
    withdraw(amount) {
        const plan = [0, 0, 0, 0, 0];
        for (let i = 4; i >= 0; i--) {
            const need = Math.min(Math.floor(amount / this.denoms[i]), this.count[i]);
            plan[i] = need;
            amount -= need * this.denoms[i];
        }
        if (amount !== 0) return [-1];
        for (let i = 0; i < 5; i++) this.count[i] -= plan[i];
        return plan;
    }
}
